import { McListItem } from '@maersk-global/mds-components-core-list-item';

/**
 * Purpose: To represent an option item within a list dropdown or select menu.
 * Category: Forms
 * When to use: When you need to display a selectable item within a dropdown or select menu.
 * When not to use: When you need to display a non-selectable item or a different layout.
 * Works with components: mc-select, mc-multi-select, mc-typeahead, mc-typeahead-multi-select
 * Alternative component names: Option Item, Select Item, Dropdown Item
 *
 * @element `mc-option`
 *
 * @slot - The default slot where main label goes.
 * @slot sublabel - The `sublabel` slot where the sublabel goes.
 * @slot icon - The `icon` slot where an `mc-icon` or any other forms of graphics go.
 * @slot trailingicon - The `trailingicon` slot where an `mc-icon` or any other forms of graphics go.
 * @slot `badge` - Used if you want to attach badge to the mc-button.
 *
 * @csspart `button` - for changing visuals of button
 * @csspart `text-and-icon` - for changing visuals of text-and-icon wrapper
 * @csspart `icon` - for changing visuals of icon
 */

export class McOption extends McListItem {}

customElements.get('mc-option') || customElements.define('mc-option', McOption);

declare global {
  interface HTMLElementTagNameMap {
    'mc-option': McOption;
  }
}
